function reviewForm() {
  var inputs = document.querySelectorAll(
    ".contract-form input, .contract-form select, .contract-form textarea"
  );
  const radioContractDiv = document.querySelector(".f-block.contract");
  inputs.forEach(function (input) {
    input.disabled = true;
  });
  conditionCheckBox.style.display = "none";
}
//edit button function
function editForm() {
  var inputs = document.querySelectorAll(
    ".contract-form input, .contract-form select, .contract-form textarea"
  );
  inputs.forEach(function (input) {
    input.disabled = false;
  });
}
var step5 = document.querySelector(".form-progress-review");
