const yourContract = document.getElementById("Your-contract");

const starterContract = document.getElementById("Starter-contract");

//name of divblock
const yourContractDiv = document.querySelector(".f-block.your-contract");
const starterContractDiv = document.querySelector(".f-block.starter-contract");

const radioContractDiv = document.querySelector(".f-block.contract");
